sys_module.content:
var CleanupChoices = Class.create();
CleanupChoices.prototype = {
  initialize: function() {
    // Auto-execute cleanup on initialization
    this.cleanupRoleChoices();
  },

  cleanupRoleChoices: function() {
    try {
      // Check if cleanup already completed
      if (gs.getProperty("x_snc_ai_learnin_4.choices_cleaned", "false") == "true") {
        gs.info('Choice cleanup already completed, skipping...');
        return 'Cleanup already completed';
      }

      // Delete old role choices that should not appear in the dropdown
      var oldRoleValues = ['developer', 'admin', 'business_analyst', 'project_manager', 'executive', 'end_user', 'all', 'all_roles'];

      var deletedCount = 0;
      for (var i = 0; i < oldRoleValues.length; i++) {
        var gr = new GlideRecord('sys_choice');
        gr.addQuery('name', 'x_snc_ai_learnin_4_ai_sessions');
        gr.addQuery('element', 'role');
        gr.addQuery('value', oldRoleValues[i]);
        gr.query();

        while (gr.next()) {
          gs.info('Deleting old role choice: ' + gr.getValue('value') + ' - ' + gr.getValue('label'));
          if (gr.deleteRecord()) {
            deletedCount++;
          }
        }
      }

      if (deletedCount > 0) {
        gs.info('Choice cleanup complete. Deleted ' + deletedCount + ' old role choice records.');
        gs.setProperty('x_snc_ai_learnin_4.choices_cleaned', 'true');
      } else {
        gs.info('No old role choices found to delete.');
      }

      return 'Cleanup complete. Deleted ' + deletedCount + ' old role choice records.';

    } catch (error) {
      gs.error('Error cleaning up role choices: ' + error.message);
      return 'Error: ' + error.message;
    }
  },

  type: 'CleanupChoices'
};
